    this.POS_COEFF_Y = null;
    this.POS_COEFF_Z = null;
    this.HAS_VELOCITY_COEFFICIENTS = false;
    this.VEL_COEFF_X = null;
    this.VEL_COEFF_Y = null;
    this.VEL_COEFF_Z = null;
    this.MAX_POSITION_RESIDUAL = 0.0;
    this.RMS_POSITION_RESIDUAL = 0.0;
  }
}


static public class PPEPositionRecordVerify
{
  static public bool Verify(Google.FlatBuffers.Verifier verifier, uint tablePos)
  {
    return verifier.VerifyTableStart(tablePos)
      && verifier.VerifyString(tablePos, 4 /*EPOCH_MID*/, true)
      && verifier.VerifyField(tablePos, 6 /*EPOCH_HALF_SPAN*/, 8 /*double*/, 8, false)
      && verifier.VerifyField(tablePos, 8 /*NUM_COEFFICIENTS*/, 2 /*ushort*/, 2, false)
      && verifier.VerifyField(tablePos, 10 /*BASIS_TYPE*/, 1 /*polynomialBasisType*/, 1, false)
      && verifier.VerifyVectorOfData(tablePos, 12 /*POS_COEFF_X*/, 8 /*double*/, true)
      && verifier.VerifyVectorOfData(tablePos, 14 /*POS_COEFF_Y*/, 8 /*double*/, true)
      && verifier.VerifyVectorOfData(tablePos, 16 /*POS_COEFF_Z*/, 8 /*double*/, true)
      && verifier.VerifyField(tablePos, 18 /*HAS_VELOCITY_COEFFICIENTS*/, 1 /*bool*/, 1, false)
      && verifier.VerifyVectorOfData(tablePos, 20 /*VEL_COEFF_X*/, 8 /*double*/, false)
      && verifier.VerifyVectorOfData(tablePos, 22 /*VEL_COEFF_Y*/, 8 /*double*/, false)
      && verifier.VerifyVectorOfData(tablePos, 24 /*VEL_COEFF_Z*/, 8 /*double*/, false)
      && verifier.VerifyField(tablePos, 26 /*MAX_POSITION_RESIDUAL*/, 8 /*double*/, 8, false)
      && verifier.VerifyField(tablePos, 28 /*RMS_POSITION_RESIDUAL*/, 8 /*double*/, 8, false)
      && verifier.VerifyTableEnd(tablePos);
  }
}
